mapper.select:
SELECT TIME as time, HOST_ID as hostId, CLUSTER_ID as clusterId, HOST_POOL_ID as hostPoolId,
OP_GROUP_ID as operatorGroupId, OP_GROUP_CODE as operatorGroupCode, DOMAIN_ID as domainId,
RX_FLOW as rxFlow, RX_PACKETS as rxPackets, TX_FLOW as txFlow, TX_PACKETS as txPackets,VSWITCH_ID as vswitchId,
VSWITCH_NAME as vswitchName, VPORT as vport, MAC as mac, TX_DROPPED_PACKETS as txDroppedPktsCount, RX_DROPPED_PACKETS as rxDroppedPktsCount,
RX_ERR as rxErrCount, TX_ERR as txErrCount, RX_BYTES as readBytes, TX_BYTES as writeBytes
FROM TBL_VSWITCH_PORT_FLOW  WHERE TIME BETWEEN ${startTime} AND ${endTime}

    AND DOMAIN_ID =${domainId}


    AND VSWITCH_NAME like #{vswitchName}


    AND VSWITCH_ID=${vswitchId}


    AND VPORT like #{vport}


    AND MAC like #{mac}


    ORDER BY ${sortField} ASC


    ORDER BY ${sortField} DESC

SELECT MAC as mac, TIME, RX_FLOW as rxFlow, TX_FLOW as txFlow
FROM TBL_VSWITCH_PORT_FLOW  WHERE TIME BETWEEN ${startTime} AND ${endTime} AND DOMAIN_ID=${domainId}

    AND MAC like #{mac}

ORDER BY TIME ASC

SELECT flow.DOMAIN_ID as domainId,  domain.uuid uuid, domain.title title, domain.host_id hostId,


        ROUND(AVG(flow.RX_FLOW),2) as rxFlow


        ROUND(AVG(flow.TX_FLOW),2) as txFlow


FROM TBL_VSWITCH_PORT_FLOW flow ,
${@com.h3c.h3cloud.performance.monitor.service.mapper.base.clickhouseMapperConstant@TBL_DOMAIN} domain
WHERE domain.id = flow.DOMAIN_ID

    AND flow.HOST_POOL_ID =${hostPoolId}


    AND flow.CLUSTER_ID =${clusterId}


    AND flow.HOST_ID =${hostId}


    AND LOCATE(#{manageExistVm}, domain.metadata)


    AND OP_GROUP_CODE LIKE #{operatorGroupCode}


    AND flow.DOMAIN_ID in (${vmIds})

AND flow.TIME BETWEEN ${startTime} AND ${endTime}
GROUP BY flow.DOMAIN_ID,domain.uuid,domain.title,domain.host_id HAVING MAX(flow.TIME) > ${endTime} - 241


        ORDER BY rxFlow DESC


        ORDER BY txFlow DESC



    LIMIT ${limit}

SELECT tv.DOMAIN_ID as domainId,
SUM(tv.rx_avg)+SUM(tv.tx_avg) allFlow,
td.uuid as uuid,td.title as title,td.host_id as hostId,td.cluster_id as clusterId,td.host_pool_id as hostPoolId
FROM (SELECT DOMAIN_ID,  ROUND(AVG(RX_FLOW),2) rx_avg,  ROUND(AVG(TX_FLOW),2) tx_avg from TBL_VSWITCH_PORT_FLOW
WHERE TIME BETWEEN ${startTime} AND ${endTime}

    AND HOST_POOL_ID =${hostPoolId}


    AND CLUSTER_ID =${clusterId}


    AND HOST_ID =${hostId}


    AND CLUSTER_ID in (${clusterIds})


    AND HOST_ID in (${hostIds})


    AND DOMAIN_ID in (${vmIds})

GROUP BY DOMAIN_ID, MAC
HAVING MAX(TIME) > ${endTime} -241
) as tv  ,${@com.h3c.h3cloud.performance.monitor.service.mapper.base.clickhouseMapperConstant@TBL_DOMAIN} td WHERE tv.DOMAIN_ID = td.id AND td.enable = 1

    AND LOCATE(#{manageExistVm}, domain.METADATA)


    AND op_group_code LIKE #{operatorGroupCode}

GROUP BY tv.DOMAIN_ID,td.uuid,td.title,td.host_id,td.cluster_id,td.host_pool_id
ORDER BY allFlow DESC

    LIMIT ${limit}

SELECT TIME as time, DOMAIN_ID as domainId, RX_FLOW as rxFlow, RX_PACKETS as rxPackets, TX_FLOW as txFlow, TX_PACKETS as txPackets,
VSWITCH_NAME as vswitchName, VPORT as vport, MAC as mac, TX_DROPPED_PACKETS as txDroppedPktsCount, RX_DROPPED_PACKETS as rxDroppedPktsCount,
RX_ERR as rxErrCount, TX_ERR as txErrCount, RX_BYTES as readBytes, TX_BYTES as writeBytes
FROM TBL_VSWITCH_PORT_FLOW tv  WHERE TIME=(SELECT MAX(TIME)-${duration} FROM TBL_VSWITCH_PORT_FLOW)

    AND tv.HOST_POOL_ID =${hostPoolId}


    AND tv.CLUSTER_ID =${clusterId}


    AND tv.HOST_ID =${hostId}


    AND tv.DOMAIN_ID =${domainId}


    AND tv.MAC = #{mac}

SELECT ROUND(AVG(tts.rate),2) as flow, tts.TIME as time from(
SELECT SUM(flow.RX_FLOW)+SUM(flow.TX_FLOW) rate,flow.TIME
FROM TBL_VSWITCH_PORT_FLOW flow,${@com.h3c.h3cloud.performance.monitor.service.mapper.base.clickhouseMapperConstant@TBL_DRX_VM}  drxVm
WHERE flow.DOMAIN_ID=drxVm.domain_id AND drxVm.drx_business_id=${drxId}
AND flow.TIME BETWEEN ${startTime} AND ${endTime}
GROUP BY flow.TIME,flow.DOMAIN_ID)tts GROUP BY tts.TIME ORDER BY tts.TIME ASC

SELECT SUM(tvpf.RX_FLOW) + SUM(tvpf.TX_FLOW) as flow, tvpf.TIME as time, domain.title as title
FROM TBL_VSWITCH_PORT_FLOW tvpf INNER JOIN ${@com.h3c.h3cloud.performance.monitor.service.mapper.base.clickhouseMapperConstant@TBL_DOMAIN}
 domain ON tvpf.DOMAIN_ID=domain.id
WHERE tvpf.DOMAIN_ID = ${domainId} AND tvpf.TIME BETWEEN ${startTime} AND ${endTime}
AND has(splitByChar(',', #{macs}), tvpf.MAC)

    AND tvpf.OP_GROUP_CODE LIKE #{operatorGroupCode}

GROUP BY tvpf.DOMAIN_ID, tvpf.TIME,domain.title  ORDER BY tvpf.TIME ASC

select DOMAIN_ID as domainId, title, any(MAC) as mac, max(avg_rate) flow from ( select tb1.DOMAIN_ID, tb2.title, tb1.MAC, round(avg(tb1.RX_FLOW + tb1.TX_FLOW),2) as avg_rate from TBL_VSWITCH_PORT_FLOW tb1 join ${@com.h3c.h3cloud.performance.monitor.service.mapper.base.clickhouseMapperConstant@TBL_DOMAIN} tb2 on tb1.DOMAIN_ID=tb2.id WHERE tb1.TIME BETWEEN ${startTime} AND ${endTime} and tb2.enable=1
and tb2.op_group_code like #{operatorGroupCode}
group by tb1.DOMAIN_ID, tb1.MAC,tb2.title) tb3 group by DOMAIN_ID,title order by flow desc limit 5

SELECT MAC as mac,DOMAIN_ID as domainId, ROUND(AVG(RX_FLOW),2) as avgRxFlow , MAX(RX_FLOW) as maxRxFlow, MIN(RX_FLOW) as minRxFlow,
ROUND(AVG(TX_FLOW),2) as avgTxFlow , MAX(TX_FLOW) as maxTxFlow, MIN(TX_FLOW) as minTxFlow
FROM TBL_VSWITCH_PORT_FLOW detail  WHERE TIME BETWEEN ${startTime} AND ${endTime}

    AND DOMAIN_ID = ${domainId}


    AND DOMAIN_ID in (${vmIds})

GROUP BY DOMAIN_ID, MAC;
